const exec = $json.execution;
const workflow = $json.workflow;

// Detect which path failed based on the failing node name.
// Reschedule-path nodes are suffixed or named with 'Reschedule'/'Form1'.
const nodeName = exec.error?.node?.name ?? 'Unknown';
const isReschedule = nodeName.includes('Reschedule') || nodeName === 'Form1' || nodeName === 'redirect to form1';
const path = isReschedule ? 'Reschedule' : 'New Client';

const mode = exec.mode === 'trigger' ? 'trigger (real submission)'
  : exec.mode === 'manual' ? 'manual (test run)'
  : exec.mode;

const now = new Date();
const timeStr = now.toLocaleString('en-US', {
  timeZone: 'YOUR_COACH_TIMEZONE',
  month: 'short',
  day: 'numeric',
  year: 'numeric',
  hour: 'numeric',
  minute: '2-digit',
  hour12: true
}) + ' (coach timezone)';

const desc = [
  'PATH',
  'Which path: ' + path,
  '',
  'WHAT FAILED',
  'Node: ' + nodeName,
  'Error: ' + (exec.error?.message ?? 'Unknown error'),
  '',
  'EXECUTION',
  'ID: ' + exec.id,
  'Mode: ' + mode,
  'Time: ' + timeStr,
  'Link: ' + (exec.url ?? 'https://YOUR_N8N_INSTANCE/workflow/' + workflow.id + '/executions/' + exec.id)
].join('\n');

const cardName = '\u26a0\ufe0f ' + path + ' path failed';

return [{ json: { cardName, desc } }];
